const Web3 = require('web3');
const { ethers } = require("ethers");

// Connect to Ethereum node
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'));

// Wallet configuration with private key (do not expose this in a real application)
const privateKey = 'YOUR_PRIVATE_KEY';
const wallet = new ethers.Wallet(privateKey);

async function sendEth(toAddress, amount) {
    const gasPrice = await web3.eth.getGasPrice();
    const gasLimit = 21000;
    const value = web3.utils.toWei(amount.toString(), 'ether');

    const tx = {
        from: wallet.address,
        to: toAddress,
        value: value,
        gas: gasLimit,
        gasPrice: gasPrice
    };

    const signedTx = await wallet.signTransaction(tx);
    const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);

    return receipt;
}

async function interactWithContract(contractAddress, abi, functionName, args) {
    const contract = new web3.eth.Contract(abi, contractAddress);

    const gasPrice = await web3.eth.getGasPrice();
    const gasEstimate = await contract.methods[functionName](...args).estimateGas({ from: wallet.address });
    const data = contract.methods[functionName](...args).encodeABI();

    const tx = {
        from: wallet.address,
        to: contractAddress,
        gas: gasEstimate,
        gasPrice: gasPrice,
        data: data
    };

    const signedTx = await wallet.signTransaction(tx);
    const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);

    return receipt;
}

